  1	import * as React from 'react';
  2	import produce from 'immer';
  3	
  4	import { NodeModel } from '@kubevirt-ui/kubevirt-api/console';
  5	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
  6	import {
  7	  K8sIoApiCoreV1Toleration,
  8	  K8sIoApiCoreV1TolerationEffectEnum,
  9	  K8sIoApiCoreV1TolerationOperatorEnum,
 10	  V1VirtualMachine,
 11	  V1VirtualMachineInstance,
 12	} from '@kubevirt-ui/kubevirt-api/kubevirt';
 13	import LabelsList from '@kubevirt-utils/components/NodeSelectorModal/components/LabelList';
 14	import NodeCheckerAlert from '@kubevirt-utils/components/NodeSelectorModal/components/NodeCheckerAlert';
 15	import { useIDEntities } from '@kubevirt-utils/components/NodeSelectorModal/hooks/useIDEntities';
 16	import ModalPendingChangesAlert from '@kubevirt-utils/components/PendingChanges/ModalPendingChangesAlert/ModalPendingChangesAlert';
 17	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 18	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 19	import { getTolerations } from '@kubevirt-utils/resources/vm';
 20	import { ensurePath, isEmpty } from '@kubevirt-utils/utils/utils';
 21	import { Form, ModalVariant, Stack, StackItem } from '@patternfly/react-core';
 22	
 23	import { TolerationLabel } from './utils/constants';
 24	import { getNodeTaintQualifier } from './utils/helpers';
 25	import TolerationEditRow from './TolerationEditRow';
 26	import TolerationListHeaders from './TolerationListHeaders';
 27	import TolerationModalDescriptionText from './TolerationModalDescriptionText';
 28	
 29	type TolerationsModalProps = {
 30	  isOpen: boolean;
 31	  nodes?: IoK8sApiCoreV1Node[];
 32	  nodesLoaded?: boolean;
 33	  onClose: () => void;
 34	  onSubmit: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine | void>;
 35	  vm?: V1VirtualMachine;
 36	  vmi?: V1VirtualMachineInstance;
 37	};
 38	
 39	const TolerationsModal: React.FC<TolerationsModalProps> = ({
 40	  isOpen,
 41	  nodes,
 42	  nodesLoaded,
 43	  onClose,
 44	  onSubmit,
 45	  vm,
 46	  vmi,
 47	}) => {
 48	  const { t } = useKubevirtTranslation();
 49	  const {
 50	    entities: tolerationsLabels,
 51	    onEntityAdd: onTolerationAdd,
 52	    onEntityChange: onTolerationChange,
 53	    onEntityDelete: onTolerationDelete,
 54	  } = useIDEntities<TolerationLabel>(
 55	    (getTolerations(vm) || []).map((toleration, id) => ({ ...toleration, id })),
 56	  );
 57	
 58	  const tolerationLabelsEmpty = tolerationsLabels?.length === 0;
 59	
 60	  const qualifiedNodes = getNodeTaintQualifier(nodes, nodesLoaded, tolerationsLabels);
 61	
 62	  const onSelectorLabelAdd = () =>
 63	    onTolerationAdd({
 64	      effect: K8sIoApiCoreV1TolerationEffectEnum.NoSchedule,
 65	      id: null,
 66	      key: '',
 67	      value: '',
 68	    });
 69	
 70	  const updatedVirtualMachine = React.useMemo(() => {
 71	    const updatedVM = produce<V1VirtualMachine>(vm, (vmDraft: V1VirtualMachine) => {
 72	      ensurePath(vmDraft, ['spec.template.spec.tolerations']);
 73	
 74	      const updatedTolerations: K8sIoApiCoreV1Toleration[] = (tolerationsLabels || []).map(
 75	        (toleration) => {
 76	          return {
 77	            ...toleration,
 78	            operator: toleration?.value
 79	              ? K8sIoApiCoreV1TolerationOperatorEnum.Equal
 80	              : K8sIoApiCoreV1TolerationOperatorEnum.Exists,
 81	          };
 82	        },
 83	      );
 84	
 85	      vmDraft.spec.template.spec.tolerations = updatedTolerations;
 86	    });
 87	    return updatedVM;
 88	  }, [tolerationsLabels, vm]);
 89	
 90	  return (
 91	    <TabModal
 92	      headerText={t('Tolerations')}
 93	      isOpen={isOpen}
 94	      modalVariant={ModalVariant.medium}
 95	      obj={updatedVirtualMachine}
 96	      onClose={onClose}
 97	      onSubmit={onSubmit}
 98	    >
 99	      <Stack hasGutter>
100	        <StackItem>{vmi && <ModalPendingChangesAlert />}</StackItem>
101	        <StackItem>
102	          <TolerationModalDescriptionText />
103	        </StackItem>
104	        <StackItem>
105	          <Form>
106	            <LabelsList
107	              addRowText={t('Add toleration')}
108	              emptyStateAddRowText={t('Add toleration to specify qualifying Nodes')}
109	              isEmpty={tolerationLabelsEmpty}
110	              model={!isEmpty(nodes) && NodeModel}
111	              onLabelAdd={onSelectorLabelAdd}
112	            >
113	              {!tolerationLabelsEmpty && (
114	                <>
115	                  <TolerationListHeaders />
116	                  {tolerationsLabels.map((label) => (
117	                    <TolerationEditRow
118	                      key={label.id}
119	                      label={label}
120	                      onChange={onTolerationChange}
121	                      onDelete={onTolerationDelete}
122	                    />
123	                  ))}
124	                </>
125	              )}
126	            </LabelsList>
127	            {!tolerationLabelsEmpty && nodesLoaded && (
128	              <NodeCheckerAlert
129	                nodesLoaded={nodesLoaded}
130	                qualifiedNodes={tolerationsLabels?.length === 0 ? nodes : qualifiedNodes}
131	              />
132	            )}
133	          </Form>
134	        </StackItem>
135	      </Stack>
136	    </TabModal>
137	  );
138	};
139	
140	export default TolerationsModal;

